    async def get_user_input(self) -> str:
        """Get user input with prompt"""
        # Ensure prints from other tasks don't corrupt the prompt UI
        with patch_stdout(raw=True):
            return await asyncio.get_event_loop().run_in_executor(
                None,
                lambda: self.session.prompt("🔧 > ", multiline=False)
            )
    
    async def process_input(self, user_input: str):
        """Process user input with intelligent routing"""
        try:
            # Initialize router if enabled
            if self.config.routing.enabled and not hasattr(self, 'router'):
                self.router = OpenCodeRouter(self.config)

            # Route the request if routing is enabled
            if self.config.routing.enabled:
                route_result = await self.router.route_request(user_input, {
                    'history': self.history.get_context(),
                    'history_available': bool(self.history.entries),
                    'last_list_count': self.history.get_last_items_count(),
                    'session_summary': getattr(self.history, 'session_summary', ''),
                    'model_config': self.config.model.__dict__,
                    'user_initiated_session': True
                })

                # Log routing decision (only if not in compact mode)
                if not getattr(self.config.interface, 'compact_mode', False):
                    console.print(f"[dim]Route: {route_result.lane.value} ({route_result.confidence:.0%})[/dim]")

                # Process based on route
                response = await self.process_routed_request(user_input, route_result)
            else:
                # Fallback to original processing
                response = await self.process_original_request(user_input)

            self.display_response(response)

        except Exception as e:
            console.print(f"[red]Error: {e}[/red]")
            try: self.session_manager.save_session_analytics()
            except Exception: pass
            # Ensure MVCO shutdown on exception
            try:
                if hasattr(self, 'mvco_orchestrator'):
                    self.mvco_orchestrator.shutdown()
            except Exception: pass

    async def process_routed_request(self, user_input: str, route_result) -> str:
        """Process request using routing information"""
        console.print("[dim]DEBUG: Entering process_routed_request[/dim]")

        # Handle recall lane with potential short-circuit
        console.print("[dim]DEBUG: Checking recall lane[/dim]")
        if route_result.lane == Lane.RECALL:
            console.print("[dim]DEBUG: Processing recall request[/dim]")
            return await self.handle_recall_request(user_input, route_result)

        # Handle other lanes with LLM processing
        console.print(f"[dim]DEBUG: Route lane is {route_result.lane}[/dim]")
        if route_result.lane in [Lane.STANDARD, Lane.DELIBERATE, Lane.TOOL_USE]:
            console.print("[dim]DEBUG: Processing LLM request[/dim]")
            return await self.handle_llm_request(user_input, route_result)

        else:
            # Fallback to original processing
            return await self.process_original_request(user_input)

    async def handle_recall_request(self, user_input: str, route_result) -> str:
        """Handle recall/memory requests with enhanced search capabilities"""

        # Apply query enhancement for better recall search
        enhanced_user_input = user_input
        # if self.config.optimization.enabled:
        #     if self.pre_rag_optimizer is None:
        #         self.pre_rag_optimizer = PreRAGOptimizer(self.config)
        #     query_optimization = await self.pre_rag_optimizer.optimize_query_enhancement(
        #         user_input, self.history.get_context() or ""
        #     )
        #     if query_optimization.quality_score > 0.7:  # Lower threshold for recall
        #         enhanced_user_input = query_optimization.optimized_content
        #         console.print(f"[dim]Recall query enhanced with {len(query_optimization.metadata.get('enhancements_applied', []))} improvements[/dim]")

        response = None
        recall_metadata = {
            'route_lane': route_result.lane.value,
            'route_confidence': route_result.confidence,
            'intent_type': getattr(route_result.intent_type, 'value', str(route_result.intent_type)) if hasattr(route_result, 'intent_type') else 'recall',
            'recall_type': 'unknown',
            'query_enhanced': enhanced_user_input != user_input
        }

        # Enhanced recall logic using new search capabilities
        route_metadata = self._as_dict(route_result.metadata)
        intent_metadata = self._as_dict(route_metadata.get('intent_metadata', {}))
        recall_type = intent_metadata.get('recall_type', 'unknown')

        if recall_type == 'count_recall' or 'how many' in enhanced_user_input.lower():
            # Enhanced count detection with qualifier support (e.g., "how many evergreen")
            q = enhanced_user_input.lower()
            qualifier = None
            try:
                import re as _re
                m = _re.search(r"how\s+many\s+([\w\s-]+?)\s+(?:did|were|are|in|from|on|of|that|which)", q)
                if m:
                    qualifier = m.group(1).strip()
            except Exception:
                qualifier = None

            if qualifier:
                # Try to count items in the last list matching qualifier keywords
                entries = self.history.entries[-1:]  # last entry only
                if entries:
                    text = entries[0].assistant_response.lower()
                    lines = [ln.strip() for ln in text.splitlines() if ln.strip().startswith('-')]
                    # simple keyword match
                    words = [w for w in qualifier.split() if len(w) > 2]
                    match_count = 0
                    for ln in lines:
                        if all(w in ln for w in words):
                            match_count += 1
                    if match_count:
                        response = f"I listed {match_count} matching '{qualifier}'."
                        recall_metadata['recall_type'] = 'qualified_count'
                        recall_metadata['items_found'] = match_count
            if response is None:
                # Fallback to generic last list count
                last_count = self.history.get_last_items_count()
                if last_count:
                    response = f"The last list contained {last_count} items."
                    recall_metadata['recall_type'] = 'count_query'
                    recall_metadata['items_found'] = last_count

        elif recall_type == 'memory_query' or any(word in enhanced_user_input.lower() for word in ['what did', 'remind me', 'recall']):
            # Use conversation search for memory queries
            search_results = self.history.search_conversations(enhanced_user_input, max_results=3)
            if search_results:
                # Extract key information from search results
                relevant_info = []
                for entry in search_results:
                    # Add both user input and response for context
                    relevant_info.append(f"User asked: {entry.user_input}")
                    relevant_info.append(f"I responded: {entry.assistant_response[:200]}...")

                response = "Based on our conversation history:\n" + "\n".join(relevant_info[:4])  # Limit output
                recall_metadata['recall_type'] = 'search_based'
                recall_metadata['matches_found'] = len(search_results)

        elif recall_type == 'previous_reference' or any(word in enhanced_user_input.lower() for word in ['last', 'previous', 'earlier']):
            # Find recent relevant context
            context = self.history.get_context(max_entries=3)
            if context:
                # Use context to answer about previous interactions
                response = f"In our recent conversation: {context[-300:]}"  # Last 300 chars of context
                recall_metadata['recall_type'] = 'context_based'

        # If no specific recall pattern matched, use conversation search
        if response is None:
            search_results = self.history.search_conversations(enhanced_user_input, max_results=2)
            if search_results:
                # Build response from search results
                best_match = search_results[0]
                response = f"I found this in our conversation: {best_match.assistant_response[:300]}"
                recall_metadata['recall_type'] = 'search_fallback'
            else:
                # Fallback to minimal LLM call with full context
                context = self.history.get_context(max_entries=5)
                if context:
                    with Status("[bold blue]Searching memory...", console=console):
                        response = await self.ollama_client.generate(
                            f"Context: {context[-800:]}\n\nUser: {enhanced_user_input}",
                            "Answer briefly from the conversation context. If no relevant information exists, say so.",
                            task_type='recall'
                        )
                    recall_metadata['recall_type'] = 'llm_recall'
                else:
                    response = "I don't have any relevant information in our conversation history."
                    recall_metadata['recall_type'] = 'no_context'

        # Add conversation entry to history
        self.history.add_entry(user_input, response, [], recall_metadata)

        # Update session intelligence tracking
        self.session_manager.update_session_intelligence(recall_metadata)

        return response

    async def handle_llm_request(self, user_input: str, route_result) -> str:
        """Handle requests requiring full LLM processing"""
        start_time = time.time()
        # Determine tool usage based on route with advanced orchestration
        tool_calls = []
        route_overrides = self._as_dict(route_result.config_overrides)
        if (route_result.lane == Lane.TOOL_USE or
            route_overrides.get('enable_tools', False)):

            # Use advanced tool orchestration
            tool_chain = await self.tool_orchestrator.analyze_tool_request(
                user_input,
                {
                    'route_lane': route_result.lane.value,
                    'intent_type': getattr(route_result.intent_type, 'value', str(route_result.intent_type)),
                    'confidence': route_result.confidence
                }
            )

            if tool_chain:
                console.print("[dim]🔧 Tool orchestration activated[/dim]")
                # Ensure required parameters are present (clarify when missing)
                try:
                    import sys as _sys, re as _re
                    exp_path = self._get_active_experiment()
                    for op in getattr(tool_chain, 'operations', []) or []:
                        if op.tool_name == 'file_write':
                            params = op.parameters or {}
                            if 'file_path' not in params and 'path' in params:
                                params['file_path'] = params.get('path')
                                params.pop('path', None)
                            fname = (params.get('file_path') or '').strip()
                            if not fname:
                                if _sys.stdin.isatty():
                                    default_name = 'app.py'
                                    try:
                                        ans = Prompt.ask("Filename to save code (for write)", default=default_name)
                                    except Exception:
                                        ans = default_name
                                    if not _re.match(r'^[A-Za-z0-9_.-]+$', ans or ""):
                                        console.print("[red]Invalid filename. Cancelling tool plan.[/red]")
                                        return "Cancelled by user"
                                    # Resolve within active experiment if available
                                    if exp_path:
                                        params['file_path'] = str((exp_path / 'code' / ans).resolve())
                                    else:
                                        # Fallback to relative under current working dir
                                        params['file_path'] = str(Path('code') / ans)
                                else:
                                    console.print("[yellow]No filename provided for file_write and no TTY to clarify. Cancelling.[/yellow]")
                                    return "Cancelled by user"
                            op.parameters = params
                except Exception as e:
                    console.print(f"[dim]Parameter normalization skipped: {e}[/dim]")
                try:
                    mode_key = getattr(self, '_current_mode', 'auto')
                except Exception:
                    mode_key = 'auto'
                # Optional confirmation in smart mode using confirmation_gate
                try:
                    if mode_key == 'smart' and getattr(tool_chain, 'requires_confirmation', False):
                        score = float(getattr(tool_chain, 'total_risk_score', 0.0))
                        risk = RiskLevel.HIGH if score > 10 else (RiskLevel.MEDIUM if score > 5 else RiskLevel.LOW)
                        ops = len(getattr(tool_chain, 'operations', []) or [])
                        op = OperationInfo(
                            operation_name="Execute Tool Chain",
                            description=f"Run {ops} tool operation(s) (risk score: {score})",
                            risk_level=risk,
                            affected_items=[getattr(self, 'model_name', 'model')],
                            consequences=["May modify files or system state depending on operations"],
                            reversible=True,
                            backup_available=True
                        )
                        if not confirmation_gate.require_confirmation(op):
                            console.print("[yellow]Tool execution cancelled[/yellow]")
                            return "Cancelled by user"
                except Exception:
                    pass
                orchestration_result = await self.tool_orchestrator.execute_tool_chain(tool_chain)

                if orchestration_result.success:
                    tool_calls = orchestration_result.results
                    console.print(f"[green]✓ Tool chain completed successfully ({orchestration_result.operations_completed} operations)[/green]")

                    # For pure tool requests, show results and return early
                    if route_result.lane == Lane.TOOL_USE:
                        for result in orchestration_result.results:
                            if result.get('success', False):
                                output = result.get('output')
                                if output and isinstance(output, str) and output.strip():
                                    console.print(f"[cyan]{output}[/cyan]")
                                else:
                                    console.print("[yellow]Tool executed successfully but produced no output[/yellow]")
                            else:
                                error = result.get('error') or result.get('output', 'Unknown error')
                                console.print(f"[red]Tool error: {error}[/red]")

                        # Add entry to history and return early for tool-only requests
                        routing_metadata = {
                            'route_lane': route_result.lane.value,
                            'route_confidence': route_result.confidence,
                            'intent_type': getattr(route_result.intent_type, 'value', str(route_result.intent_type)),
                            'tool_only': True
                        }
                        self.history.add_entry(user_input, "Tool execution completed", tool_calls, routing_metadata)
                        self.session_manager.update_session_intelligence(routing_metadata)
                        return "Tool execution completed"
                else:
                    console.print(f"[red]✗ Tool chain failed ({orchestration_result.operations_failed} failures)[/red]")
                    for error in orchestration_result.errors:
                        console.print(f"[red]  Error: {error}[/red]")
            elif self.should_use_tools(user_input):
                # Fallback to simple tool execution
                tool_calls = await self.execute_relevant_tools(user_input)

        # Apply Pre-RAG optimization to user query (guarded)
        optimized_user_input = user_input
        try:
            if getattr(self.config.optimization, 'enabled', False):
                if not hasattr(self, 'pre_rag_optimizer') or self.pre_rag_optimizer is None:
                    self.pre_rag_optimizer = PreRAGOptimizer(self.config)
                query_optimization = await self.pre_rag_optimizer.optimize_query_enhancement(
                    user_input, self.history.get_context() or ""
                )
                quality_score = getattr(query_optimization, 'quality_score', 0.0)
                optimized_content = getattr(query_optimization, 'optimized_content', None)
                if isinstance(quality_score, (int, float)) and quality_score >= 0.8 and optimized_content and optimized_content != user_input:
                    optimized_user_input = optimized_content
                    if not getattr(self.config.interface, 'compact_mode', False):
                        console.print(f"[dim]Query optimized (q={quality_score:.2f})[/dim]")
        except Exception as e:
            console.print(f"[dim]Pre-RAG optimization failed: {e}[/dim]")

        # Get and process context with intelligent scoring and Pre-RAG optimization
        # Context window and summary depend on mode
        # Compute auto policy for this request
        try:
            # Extract requested_count if present
            req_count = None
            try:
                intent_meta = self._as_dict(self._as_dict(route_result.metadata).get('intent_metadata', {}))
                req_count = intent_meta.get('requested_count')
            except Exception:
                pass

            prof = resource_manager.get_profile_by_percentage(self.config.runtime.resources)
            # Prepare richer inputs where available
            # Context score (if calculated above)
            _ctx_score_val = None
            try:
                _ctx_score_val = float(context_score.final_score) if 'context_score' in locals() else None
            except Exception:
                _ctx_score_val = None
            # MVCO confidence (if available)
            _mvco_conf = None
            try:
                _mvco_conf = float(safe_mvco.get('confidence', 0.0)) if 'safe_mvco' in locals() else None
            except Exception:
                _mvco_conf = None
            # Memory pressure
            try:
                mem = resource_manager.check_memory_usage()
                _mem_pressure = float(100.0 - mem.get('free_percent', 100.0))
            except Exception:
                _mem_pressure = None
            # Time budget rough estimate from resource level
            _time_budget_ms = 30000
            try:
                res = int(self.config.runtime.resources)
                _time_budget_ms = 15000 if res <= 25 else (30000 if res <= 50 else (60000 if res <= 75 else 120000))
            except Exception:
                pass

            if not hasattr(self, 'policy_provider') or self.policy_provider is None:
                # Select provider from config
                provider_name = getattr(getattr(self.config, 'policy', None), 'provider', 'basic')
                self.policy_provider = AdaptivePolicyProvider() if str(provider_name).lower() in ('advanced','adaptive') else BasicPolicyProvider()

            policy_inputs = PolicyInputs(
                mode=getattr(self, '_current_mode', 'auto'),
                lane=safe_lane,
                requested_count=req_count,
                complexity_score=getattr(complexity_result, 'total_score', 0.0),
                resources_percent=self.config.runtime.resources,
                model_temperature=self.config.model.temperature,
                model_max_tokens=self.config.model.max_tokens,
                num_ctx=prof.max_context_tokens,
                num_thread=prof.num_threads,
                context_score=_ctx_score_val,
                route_confidence=float(getattr(route_result, 'confidence', 0.0)),
                time_budget_ms=_time_budget_ms,
                qr_tier=None,
                optimizer_hints=None,
                rag_relevance=None,
                latency_observed_ms=None,
                mvco_confidence=_mvco_conf,
                memory_pressure=_mem_pressure,
            )
            # Allow policy disabling
            if getattr(self.config, 'policy', None) and not self.config.policy.enabled:
                raise RuntimeError('Policy disabled')
            policy = self.policy_provider.decide(policy_inputs)
            # Minimal policy decision log to verify wiring
            try:
                ov = self._as_dict(getattr(policy, 'overrides', {}))
                console.print(
                    f"[dim]Policy: mode={policy_inputs.mode} lane={getattr(safe_lane, 'value', safe_lane)} "
                    f"N={policy_inputs.requested_count or 0} tokens={ov.get('num_predict_override')} "
                    f"ctx={getattr(policy, 'context_entries', '?')}/"
                    f"{getattr(policy, 'include_summary', False)} budget={getattr(policy, 'token_budget', None)}[/dim]"
                )
            except Exception:
                pass
        except Exception:
            # Safe fallback
            class _Tmp: pass
            policy = _Tmp()
            policy.context_entries, policy.include_summary = 2, False
            policy.directive, policy.overrides, policy.options_override = '', {}, {}

        # Fit context to budget when available (approximate by tokens)
        token_budget = getattr(policy, 'token_budget', None)
        context = self.history.get_context(
            max_entries=policy.context_entries,
            include_summary=policy.include_summary,
            token_budget=token_budget
        )
        if context:
            # Optionally apply Pre-RAG optimization to context
            try:
                if getattr(self.config.optimization, 'enabled', False):
                    max_context_tokens = getattr(self.config.optimization, 'max_context_tokens', 2000)
                    if isinstance(max_context_tokens, int) and len(context.split()) > max_context_tokens:
                        console.print("[dim]🧠 Applying Pre-RAG optimization to context...[/dim]")
                        if not hasattr(self, 'pre_rag_optimizer') or self.pre_rag_optimizer is None:
                            self.pre_rag_optimizer = PreRAGOptimizer(self.config)
                        context_optimization = await self.pre_rag_optimizer.optimize_content_comprehensive(
                            context,
                            ContentType.CONVERSATION,
                            target_size=max_context_tokens * 4,
                            optimization_level="balanced"
                        )
                        candidate = getattr(context_optimization, 'optimized_content', None)
                        if candidate:
                            context = candidate
                            if not getattr(self.config.interface, 'compact_mode', False):
                                cs = getattr(context_optimization, 'compression_ratio', 0.0)
                                qs = getattr(context_optimization, 'quality_score', 0.0)
                                console.print(f"[dim]Context optimized: {cs:.1%} compressed, quality {qs:.2f}[/dim]")
            except Exception as e:
                console.print(f"[dim]Context optimization skipped: {e}[/dim]")

            # Initialize context management system if enabled
            if self.config.optimization.context_scoring and not hasattr(self, 'context_scorer'):
                self.context_scorer = AdaptiveContextScorer(self.config)
                self.context_pruner = DynamicContextPruner()

            # Apply intelligent context management
            if self.config.optimization.context_scoring:
                # Score context quality before processing
                context_score = self.context_scorer.score_context_quality(
                    context, getattr(route_result.intent_type, 'value', str(route_result.intent_type)), user_input
                )

                # Apply dynamic pruning if needed or score is low
                max_context_tokens = self.config.optimization.max_context_tokens
                should_prune = (
                    len(context.split()) > max_context_tokens or
                    not context_score.target_met
                )

                if should_prune and self.config.optimization.dynamic_pruning:
                    original_context = context
                    context = self.context_pruner.prune_context_intelligently(
                        context, max_context_tokens, getattr(route_result.intent_type, 'value', str(route_result.intent_type))
                    )

                    # Log pruning efficiency
                    if self.config.optimization.performance_monitoring:
                        pruned_score = self.context_scorer.score_context_quality(
                            context, getattr(route_result.intent_type, 'value', str(route_result.intent_type)), user_input
                        )
                        efficiency = self.context_pruner.calculate_pruning_efficiency(
                            original_context, context, context_score.final_score, pruned_score.final_score
                        )
                        console.print(f"[dim]Context optimized: {efficiency['compression_ratio']:.1%} compressed, "
                                    f"{efficiency['score_preservation']:.1%} quality preserved[/dim]")

                # Display context quality feedback (only if not in compact mode)
                if self.config.optimization.performance_monitoring and not getattr(self.config.interface, 'compact_mode', False):
                    quality_color = "green" if context_score.target_met else "yellow"
                    console.print(f"[{quality_color}]Context: {context_score.final_score:.0f}/{context_score.metadata['target_score']:.0f}[/{quality_color}]")

            else:
                # Fallback to simple truncation
                safe_metadata = self._as_dict(route_result.metadata)
                max_context = safe_metadata.get('max_tokens', 2000)
                if len(context.split()) > max_context:
                    context = self.truncate_context_safely(context, max_context)

            context += "\n\n"

        # Build tool context
        tool_context = ""
        if tool_calls:
            tool_context = "\n\nTool Results:\n"
            for tool_call in tool_calls:
                tool_context += f"- {tool_call['tool']}: {tool_call['result']['output'][:200]}...\n"

        # Governor: preflight estimate for long jobs; prompt in smart mode
        try:
            req_n = int(self._as_dict(self._as_dict(route_result.metadata).get('intent_metadata', {})).get('requested_count', 0))
        except Exception:
            req_n = 0
        try:
            complexity = float(getattr(complexity_result, 'total_score', 0.0))
        except Exception:
            complexity = 0.0
        current_mode = getattr(self, '_current_mode', 'auto')
        if current_mode == 'smart' and (req_n >= 200 or complexity > 0.8):
            # Estimate soft budget in minutes
            est_secs = req_n * 0.15 * (1.0 + 0.5 * complexity)
            est_min = max(1, int(est_secs // 60) + 1)
            op = OperationInfo(
                operation_name="Long Generation",
                description=f"Generate {req_n or 'many'} items with deep reasoning",
                risk_level=RiskLevel.MEDIUM,
                affected_items=[f"mode: {current_mode}", f"estimated: ~{est_min}m"],
                consequences=["Long-running generation", "May produce large output"],
                reversible=True,
                backup_available=True,
                estimated_time=f"~{est_min} minutes"
            )
            if confirmation_gate.require_confirmation(op):
                # Switch to think with suggested time budget (soft)
                self._current_mode = 'think'
                self._think_budget_secs = est_min * 60
                console.print(f"[dim]Switching to think mode with soft budget ~{est_min}m[/dim]")
            else:
                console.print("[yellow]Cancelled long generation[/yellow]")
                return "Cancelled by user"

        # Build full prompt with optimized components
        # If structured mode, add a strict formatting directive to reduce verbosity
        directive = policy.directive if route_overrides.get('structured_mode') else ''
        # Add ThinkTime budget directive so the model is aware of soft limits
        try:
            if getattr(self, '_current_mode', 'auto') == 'think':
                max_secs = getattr(self, '_think_budget_max_secs', None)
                min_secs = getattr(self, '_think_budget_min_secs', None)
                if max_secs or min_secs:
                    parts = []
                    if max_secs:
                        parts.append(f"wrap up before ~{max_secs}s")
                    if min_secs:
                        parts.append(f"utilize at least ~{min_secs}s to think")
                    if parts:
                        directive += ("\n\nInstructions: "
                                      "Be aware of a soft time budget; "
                                      + ", ".join(parts)
                                      + ". If time is insufficient, provide partial results, list unmet goals, and ask clarifying questions.")
        except Exception:
            pass
        full_prompt = context + tool_context + f"User: {optimized_user_input}{directive}"

        # Generate response with lane-specific parameters (guard enum/string)
        lane_mapping = {
            Lane.STANDARD: 'structured' if route_overrides.get('structured_mode') else 'standard',
            Lane.DELIBERATE: 'reasoning',
            Lane.TOOL_USE: 'tool_use'
        }
        safe_lane = getattr(route_result, 'lane', Lane.STANDARD)
        try:
            # If lane is a string, coerce to default mapping
            if isinstance(safe_lane, str):
                inv = {
                    'standard': Lane.STANDARD,
                    'deliberate': Lane.DELIBERATE,
                    'tool_use': Lane.TOOL_USE,
                    'recall': getattr(Lane, 'RECALL', Lane.STANDARD)
                }
                safe_lane = inv.get(safe_lane.lower(), Lane.STANDARD)
        except Exception:
            safe_lane = Lane.STANDARD
        task_type = lane_mapping.get(safe_lane, 'standard')

        # Show appropriate status message
        status_messages = {
            Lane.STANDARD: "[bold green]Processing...",
            Lane.DELIBERATE: "[bold yellow]Analyzing...",
            Lane.TOOL_USE: "[bold cyan]Using tools..."
        }

        # Step: Complexity Analysis and Resource Optimization
        complexity_result = complexity_analyzer.analyze_complexity(
            user_input,
            self.history.get_context() or ""
        )

        # Apply smart mode or complexity-based adjustments
        original_resources = self.config.runtime.resources
        current_mode = getattr(self, '_current_mode', 'auto')

        if current_mode == 'smart':
            # Smart mode: use complexity-recommended resources
            self.config.runtime.resources = complexity_result.recommended_percentage
            self._update_orchestrator_resources()
            self._update_ollama_timeout_for_mode()
            console.print(f"[dim]🤖 Smart allocation: {complexity_result.recommended_percentage}% (complexity: {complexity_result.total_score:.2f})[/dim]")

        elif current_mode == 'think' and complexity_result.total_score > 0.6:
            # High complexity in think mode - may increase resources
            enhanced_percentage = min(75, complexity_result.recommended_percentage + 10)
            if enhanced_percentage > self.config.runtime.resources:
                self.config.runtime.resources = enhanced_percentage
                self._update_orchestrator_resources()
                console.print(f"[dim]Enhanced allocation: {enhanced_percentage}% (high complexity detected)[/dim]")

        # Step: MVCO Prediction (if enabled) - skip in fast mode to reduce overhead
        mvco_model_suggestion = None
        if getattr(self.config.routing, 'use_mvco_router', True) and current_mode != 'fast':
            try:
                mvco_prediction = self.mvco_orchestrator.predict_next_state(user_input)
                safe_mvco_prediction = self._as_dict(mvco_prediction)
                mvco_model_suggestion = safe_mvco_prediction.get('recommended_model')
                confidence = safe_mvco_prediction.get('confidence', 0.0)

                if confidence > 0.3:  # Only use predictions with reasonable confidence
                    if not getattr(self.config.interface, 'compact_mode', False):
                        model_short = mvco_model_suggestion.split(':')[0] if mvco_model_suggestion else 'Unknown'
                        console.print(f"[dim]MVCO: {model_short} ({confidence:.0%})[/dim]")
                else:
                    mvco_model_suggestion = None
            except Exception as e:
                console.print(f"[dim]MVCO error: {e}[/dim]")

        # Step: Dynamic Quantization Management (log-only; skip in fast)
        # Only use auto model selection if enabled (for kiosk mode)
        auto_selection_enabled = getattr(self.config.interface, 'auto_model_selection', False)
        if current_mode != 'fast' and auto_selection_enabled and mvco_model_suggestion:
            selected_model = mvco_model_suggestion
        else:
            selected_model = self.config.model.name
        try:
            # Get priority based on current mode and complexity
            if current_mode == 'fast':
                priority = 'speed'
            elif complexity_result.total_score > 0.7:
                priority = 'quality'
            else:
                priority = 'balanced'

            # Get quantization recommendation for the base model (log-only, no pulling)
            base_model = selected_model.split(':')[0] if ':' in selected_model else selected_model
            if current_mode != 'fast':
                quant_recommendation = self.quant_manager.recommend_quantization(
                    base_model,
                    target_context=4096,
                    priority=priority
                )
                if quant_recommendation.get('recommended_model') and not getattr(self.config.interface, 'compact_mode', False):
                    model_short = quant_recommendation['recommended_model'].split(':')[0]
                    console.print(f"[dim]Quant rec: {model_short}[/dim]")

        except Exception as e:
            console.print(f"[dim]Quantization error: {e}, using original model[/dim]")

        # Step: MVCO Predictive Routing
        mvco_prediction = None
        routing_cfg = getattr(self.config, "routing", None)
        mvco_on = getattr(routing_cfg, "use_mvco_router", False)
        if mvco_on:
            mvco_prediction = self.mvco_orchestrator.predict_next_state(user_input)
            safe_mvco = self._as_dict(mvco_prediction)
            if safe_mvco and safe_mvco.get('confidence', 0) > 0.7:
                # Potentially override model selection or routing based on MVCO prediction
                console.print(f"[dim]MVCO Prediction: {safe_mvco.get('recommended_model')} (Confidence: {safe_mvco.get('confidence', 0):.2f})[/dim]")
                # For now, just log the prediction. Actual override will be in a later phase.

        # Minimal observability for model call
        def _safe_log_input(txt: str) -> str:
            try:
                snippet = txt.replace('\n', ' ')[:80]
                return snippet + ("..." if len(txt) > 80 else "")
            except Exception:
                return "<unprintable>"

        with Status(status_messages.get(safe_lane, "[bold green]Thinking..."), console=console):
            # Temporarily override model name for this generation
            original_model = self.config.model.name
            self.config.model.name = selected_model
            try:
                start_time = time.time()
                # Resource profile display (live)
                try:
                    prof_now = resource_manager.get_profile_by_percentage(self.config.runtime.resources)
                    console.print(f"[dim]Resources: threads={prof_now.num_threads}, ctx={prof_now.max_context_tokens} tokens[/dim]")
                except Exception:
                    pass
                # Log only current user request; summarize context size to avoid confusion
                try:
                    ctx_user_lines = [ln for ln in (context or '').splitlines() if ln.startswith('User: ')]
                    ctx_count = len(ctx_user_lines)
                except Exception:
                    ctx_count = 0
                console.print(f"[dim]Model call: 'User: {_safe_log_input(optimized_user_input)}' (ctx: {ctx_count}, type: {task_type})[/dim]")
                # In fast/auto structured simple lists, bypass quality manager for minimal overhead
                fast_bypass = (
                    (current_mode in ('fast', 'auto'))
                    and route_overrides.get('structured_mode')
                    and getattr(complexity_result, 'total_score', 0.0) < 0.5
                )
                if self.quality_manager and not fast_bypass:
                    # Quality path will eventually call original generator; it computes its own caps
                    qm_overrides = {}
                    try:
                        use_overrides = bool(getattr(getattr(self.config, 'policy', None), 'enabled', True))
                        if use_overrides:
                            qm_overrides = dict(policy.overrides)
                            if policy.options_override and getattr(self.config.policy, 'allow_options_override', True):
                                qm_overrides['options_override'] = policy.options_override
                    except Exception:
                        qm_overrides = {}
                    response = await self.quality_manager.enhanced_generate(
                        full_prompt,
                        self.config.system_prompt,
                        task_type=task_type,
                        overrides=qm_overrides
                    )
                else:
                    use_overrides = bool(getattr(getattr(self.config, 'policy', None), 'enabled', True))
                    overrides = dict(policy.overrides) if use_overrides else {}
                    # Honor config flag for backend options override
                    if use_overrides and policy.options_override and getattr(self.config.policy, 'allow_options_override', True):
                        overrides['options_override'] = policy.options_override
                    # Route through _generate_with_resources to ensure streaming/thinktime enforcement
                    response = await self._generate_with_resources(
                        full_prompt,
                        self.config.system_prompt,
                        task_type,
                        overrides=overrides,
                    )
                duration = time.time() - start_time
                try:
                    # Record version test metrics if active
                    if getattr(self.version_manager, 'active_id', None):
                        self.version_manager.record_metric(duration)
                except Exception:
                    pass
                console.print(f"[dim]Model response: {len(str(response))} chars in {duration:.1f}s[/dim]")
            finally:
                # Restore original model name
                self.config.model.name = original_model

        # Strict N enforcement for structured lists
        try:
            if route_overrides.get('structured_mode'):
                intent_meta = self._as_dict(self._as_dict(route_result.metadata).get('intent_metadata', {}))
                req_n = int(intent_meta.get('requested_count', 0))
                if req_n and isinstance(response, str):
                    fixed = self._enforce_hyphen_bullets(response, req_n)
                    if fixed is not None and fixed != response:
                        response = fixed
                        console.print(f"[dim]Adjusted list to exactly {req_n} items[/dim]")
        except Exception:
            pass

        # Step: Think Mode Verification (if enabled and appropriate)
        verification_report = None
        if (current_mode == 'think' and
            complexity_result.total_score > 0.4 and
            any(ct.value in ['research', 'analytical', 'technical'] for ct in complexity_result.complexity_types)):

            console.print("[dim]🔍 Running verification analysis...[/dim]")

            research_context = ResearchContext(
                original_query=user_input,
                research_findings=response,
                reasoning_process=response,  # Could be enhanced with separate reasoning tracking
                sources_cited=[],  # Could be enhanced with source extraction
                complexity_score=complexity_result.total_score,
                research_depth="moderate"
            )

            verification_report = await verification_engine.verify_research_workflow(research_context)

            if verification_report.result.value != 'verified':
                console.print(f"[yellow]Verification: {verification_report.result.value.upper()} (confidence: {verification_report.confidence_score:.2f})[/yellow]")

                if verification_report.recommendations:
                    console.print("[yellow]Recommendations:[/yellow]")
                    for rec in verification_report.recommendations[:2]:  # Show top 2
                        console.print(f"[dim]  {rec}[/dim]")

        # Plan Phase: propose plan when strong indicators exist (active experiment + code intent)
        try:
            if getattr(self.config.interface, 'auto_suggest_tools', False):
                import sys as _sys, re as _re
                exp_path = self._get_active_experiment()
                blocks = self._extract_code_blocks(response) if isinstance(response, str) else []
                verbs = ['build', 'create', 'make', 'generate']
                nouns = ['app', 'script', 'program']
                nl = (not user_input.lstrip().startswith('/'))
                intent_trigger = any(v in user_input.lower() for v in verbs) and any(n in user_input.lower() for n in nouns)
                code_trigger = (len(blocks) == 1) or (self._looks_like_python_snippet(response) and route_result.lane == Lane.DELIBERATE)
                if exp_path and nl and (code_trigger or intent_trigger) and _sys.stdin.isatty():
                    console.print("[bold cyan]📝 Plan[/bold cyan]")
                    console.print(f"[dim]Task:[/dim] {user_input[:120]}{'...' if len(user_input)>120 else ''}")
                    console.print(f"[dim]Assumptions:[/dim] python, single file, stdlib-only")
                    console.print(f"[dim]Destination:[/dim] {exp_path / 'code'}")
                    console.print(f"[dim]Steps:[/dim] 1) Obtain code  2) Save  3) Run  4) Verify")
                    # Collect code to save
                    code_text = None
                    default_name = 'app.py'
                    if len(blocks) == 1:
                        code_text = blocks[0]['code']
                        lang = blocks[0]['lang'] or 'python'
                        if lang not in ('', 'python', 'py'):
                            default_name = f"app.{lang}"
                    # Options
                    console.print("[dim]Options: [1] Proceed (save & run)  [2] Choose filename  [3] Ask model to reformat to single fenced block  [4] Cancel[/dim]")
                    choices = ["1","2","3","4"] if code_text else ["2","3","4"]
                    try:
                        choice = Prompt.ask("Select option", choices=choices, default=("1" if code_text else "3"))
                    except Exception:
                        choice = "4"
                    if choice != "4":
                        # Reformat if needed or requested
                        if choice == "3" or code_text is None:
                            try:
                                ref_prompt = "Reformat the following into one single fenced python code block (```python ... ```), output only the block and nothing else. Keep under 220 lines.\n\n" + (response if isinstance(response, str) else "")
                                reformatted = await self._generate_with_resources(ref_prompt, self.config.system_prompt, 'standard')
                                new_blocks = self._extract_code_blocks(reformatted)
                                if len(new_blocks) == 1:
                                    code_text = new_blocks[0]['code']
                                else:
                                    console.print("[yellow]Could not obtain a single fenced block. Aborting plan.[/yellow]")
                                    code_text = None
                            except Exception as e:
                                console.print(f"[red]Reformat failed: {e}[/red]")
                                code_text = None
                        if code_text:
                            filename = default_name
                            if choice in ("2",):
                                try:
                                    filename = Prompt.ask("Filename", default=default_name)
                                except Exception:
                                    filename = default_name
                            if not _re.match(r'^[A-Za-z0-9_.-]+$', filename or ""):
                                console.print("[red]Invalid filename. Aborting save.[/red]")
                            else:
                                dest = (exp_path / 'code' / filename).resolve()
                                # Confirm write
                                op = OperationInfo(
                                    operation_name="Save Code (Plan)",
                                    description=f"Write {filename} in active experiment",
                                    risk_level=RiskLevel.MEDIUM,
                                    affected_items=[str(dest)],
                                    consequences=["File will be created or overwritten"],
                                    reversible=True,
                                    backup_available=True
                                )
                                if confirmation_gate.require_confirmation(op):
                                    try:
                                        self.tool_manager.working_dir = exp_path.resolve()
                                        write_res = await self.tool_manager.execute_tool('file_write', file_path=str(dest), content=code_text, create_dirs=True)
                                        if write_res.success:
                                            console.print(f"[green]✓ Saved {dest}[/green]")
                                            # Confirm run
                                            run_op = OperationInfo(
                                                operation_name="Run Saved Script (Plan)",
                                                description=f"Execute {filename} in active experiment",
                                                risk_level=RiskLevel.LOW,
                                                affected_items=[str(dest)],
                                                consequences=["Script will run and may write outputs"],
                                                reversible=True,
                                                backup_available=True
                                            )
                                            if confirmation_gate.require_confirmation(run_op):
                                                interp = self._python_interpreter()
                                                res = await self.tool_manager.execute_tool('bash_execute', command=f"{interp} {dest.name}", cwd=str((exp_path / 'code').resolve()))
                                                if res.success:
                                                    if res.output:
                                                        console.print(f"[cyan]{res.output}\n[/cyan]")
                                                    else:
                                                        console.print("[green]✓ Script finished[/green]")
                                                else:
                                                    console.print(f"[red]Execution failed: {res.error}[/red]")
                                        else:
                                            console.print(f"[red]Write failed: {write_res.error}[/red]")
                                    except Exception as e:
                                        console.print(f"[red]Plan execution error: {e}[/red]")
        except Exception as e:
            console.print(f"[dim]Plan flow skipped: {e}[/dim]")

        # Prepare routing metadata
        routing_metadata = {
            'route_lane': route_result.lane.value,
            'route_confidence': route_result.confidence,
            'intent_type': getattr(route_result.intent_type, 'value', str(route_result.intent_type)),
            'complexity_score': complexity_result.total_score,
            'complexity_types': [t.value for t in complexity_result.complexity_types],
            'resource_adjustment': self.config.runtime.resources != original_resources,
            'allocated_resources': self.config.runtime.resources,
            'verification_result': verification_report.result.value if verification_report else None,
            'verification_confidence': verification_report.confidence_score if verification_report else None
        }

        # Add entry to history with routing metadata
        self.history.add_entry(user_input, response, tool_calls, routing_metadata)

        # Update session intelligence tracking
        self.session_manager.update_session_intelligence(routing_metadata)

        # Clear ephemeral ThinkTime budgets after this run
        try:
            self._think_budget_max_secs = None
            self._think_budget_min_secs = None
        except Exception:
            pass

        # MVCO Learning Feedback
        if mvco_on and mvco_prediction:
            safe_routing_metadata = self._as_dict(routing_metadata)
            quality_score = safe_routing_metadata.get('quality_score', 0.0)

            self.mvco_orchestrator.add_interaction(
                prompt=user_input,
                response=response,
                model_used=self.config.model.name,
                response_time=(time.time() - start_time), # Assuming start_time is captured earlier
                quality_score=quality_score
            )

        return response

    async def process_original_request(self, user_input: str) -> str:
        """Original processing logic as fallback"""
        tool_calls = []
        if self.should_use_tools(user_input):
            tool_calls = await self.execute_relevant_tools(user_input)

        context = self.history.get_context()
        if context:
            context = self.truncate_context_safely(context, max_chars=2000)
            context += "\n\n"

        tool_context = ""
        if tool_calls:
            tool_context = "\n\nTool Results:\n"
            for tool_call in tool_calls:
                tool_context += f"- {tool_call['tool']}: {tool_call['result']['output'][:200]}...\n"

        full_prompt = context + tool_context + f"User: {user_input}"

        with Status("[bold green]Thinking...", console=console):
            if self.quality_manager:
                response = await self.quality_manager.enhanced_generate(full_prompt, self.config.system_prompt)
            else:
                response = await self.ollama_client.generate(full_prompt, self.config.system_prompt)

        self.history.add_entry(user_input, response, tool_calls)
        return response

    def should_use_tools(self, user_input: str) -> bool:
        """Determine if tools should be used based on user input"""
        tool_keywords = [
            'read', 'write', 'edit', 'file', 'search', 'find', 'grep',
            'run', 'execute', 'command', 'bash', 'git', 'status', 'diff'
        ]
        
        return any(keyword in user_input.lower() for keyword in tool_keywords)
    
    async def execute_relevant_tools(self, user_input: str) -> List[Dict]:
        """Execute relevant tools based on user input"""
        tool_calls = []
        
        if 'read' in user_input.lower() or 'show' in user_input.lower():
            words = user_input.split()
            for word in words:
                if '.' in word and not word.startswith('http'):
                    result = await self.tool_manager.execute_tool('file_read', file_path=word)
                    tool_calls.append({'tool': 'file_read', 'params': {'file_path': word}, 'result': result})
                    break
        
        elif 'search' in user_input.lower() or 'find' in user_input.lower():
            words = user_input.split()
            if len(words) > 1:
                pattern = words[-1]
                result = await self.tool_manager.execute_tool('grep_search', pattern=pattern)
                tool_calls.append({'tool': 'grep_search', 'params': {'pattern': pattern}, 'result': result})
        
        elif 'git' in user_input.lower():
            if 'status' in user_input.lower():
                result = await self.tool_manager.execute_tool('git_operations', operation='status')
                tool_calls.append({'tool': 'git_operations', 'params': {'operation': 'status'}, 'result': result})
            elif 'diff' in user_input.lower():
                result = await self.tool_manager.execute_tool('git_operations', operation='diff')
                tool_calls.append({'tool': 'git_operations', 'params': {'operation': 'diff'}, 'result': result})
        
        return tool_calls

    # ====== Suggestion helpers ======
    def _extract_code_blocks(self, text: str):
        try:
            import re
            pattern = re.compile(r"```([a-zA-Z0-9_+.-]*)\n([\s\S]*?)```", re.MULTILINE)
            blocks = []
            for m in pattern.finditer(text or ""):
                lang = (m.group(1) or '').strip().lower()
                code = m.group(2)
                if code and code.strip():
                    blocks.append({'lang': lang, 'code': code})
            return blocks
        except Exception:
            return []

    def _get_active_experiment(self):
        try:
            import os, json
            ver = os.getenv('OPENCODE_VERSION', '').strip() or 'default'
            state_path = Path('versions') / ver / 'experiments' / '.state.json'
            if state_path.exists():
                data = json.loads(state_path.read_text())
                exp = data.get('active_experiment')
                if exp and Path(exp).is_dir():
                    return Path(exp)
        except Exception:
            return None
        return None

    def _python_interpreter(self) -> str:
        """Choose a Python interpreter available on PATH, preferring python3."""
        try:
            import shutil
            if shutil.which('python3'):
                return 'python3'
            if shutil.which('python'):
                return 'python'
        except Exception:
            pass
        # Fallback to 'python' (may fail if not present)
        return 'python'

    def _looks_like_python_snippet(self, text: str) -> bool:
        try:
            if not isinstance(text, str):
                return False
            low = text.lower()
            indicators = ['import argparse', 'if __name__ == "__main__"', 'def main(', 'from pathlib import', 'import os', 'import sys']
            return any(tok in low for tok in indicators)
        except Exception:
            return False

    def display_response(self, response: str):
        """Display the assistant's response"""
        if self.config.interface.compact_mode:
            if self.config.interface.syntax_highlighting and (response.strip().startswith('```') or 'def ' in response or 'class ' in response):
                if response.strip().startswith('```'):
                    lines = response.split('\n')
                    if len(lines) > 1:
                        lang = lines[0].replace('```', '').strip()
                        code = '\n'.join(lines[1:-1]) if lines[-1].strip() == '```' else '\n'.join(lines[1:])
                        console.print(Syntax(code, lang or "python", theme="monokai"))
                    else:
                        console.print(response)
                else:
                    console.print(Syntax(response, "python", theme="monokai"))
            else:
                console.print(response)
        else:
            if self.config.interface.syntax_highlighting and (response.strip().startswith('```') or 'def ' in response or 'class ' in response):
                if response.strip().startswith('```'):
                    lines = response.split('\n')
                    if len(lines) > 1:
                        lang = lines[0].replace('```', '').strip()
                        code = '\n'.join(lines[1:-1]) if lines[-1].strip() == '```' else '\n'.join(lines[1:])
                        console.print(Syntax(code, lang or "python", theme="monokai"))
                    else:
                        console.print(Markdown(response))
                else:
                    console.print(Syntax(response, "python", theme="monokai"))
            else:
                console.print(Markdown(response))
    
