    def show_history(self):
        """Show current session conversation history"""
        if not self.history.entries:
            console.print("[yellow]No conversation history in current session[/yellow]")
            console.print(f"[dim]Current session: {self.history.current_session_id or 'None'}[/dim]")
            console.print(f"[dim]Model: {self.config.model.name}[/dim]")
            console.print("[dim]Use '/history list' to see all sessions[/dim]")
            return

        # Show session info
        console.print(f"[cyan]Session: {self.history.current_session_id}[/cyan]")
        console.print(f"[dim]Model: {self.config.model.name} | Entries: {len(self.history.entries)}[/dim]")
        if self.history.session_metadata.get('created'):
            created = datetime.fromisoformat(self.history.session_metadata['created']).strftime("%Y-%m-%d %H:%M")
            console.print(f"[dim]Created: {created}[/dim]")

        # Show conversation table
        table = Table(title="Current Session History")
        table.add_column("Time", style="dim")
        table.add_column("User Input", style="cyan")
        table.add_column("Response", style="green")

        for entry in self.history.entries[-10:]:
            timestamp = datetime.fromisoformat(entry.timestamp).strftime("%H:%M:%S")
            user_input = entry.user_input[:50] + "..." if len(entry.user_input) > 50 else entry.user_input
            response = entry.assistant_response[:50] + "..." if len(entry.assistant_response) > 50 else entry.assistant_response
            table.add_row(timestamp, user_input, response)

        console.print(table)

        if len(self.history.entries) > 10:
            console.print(f"[dim]Showing last 10 of {len(self.history.entries)} entries[/dim]")

    async def handle_history_command(self, command: str):
        """Handle enhanced history commands"""
        parts = command.split()
        if not parts:
            self.show_history()
            return

        action = parts[0].lower()

        if action == 'list':
            await self.show_all_sessions()
        elif action == 'sessions':
            await self.show_sessions_by_model()
        elif action == 'load' and len(parts) > 1:
            session_id = parts[1]
            await self.load_session(session_id)
        elif action == 'export':
            session_id = parts[1] if len(parts) > 1 else None
            await self.export_session(session_id)
        elif action == 'clear':
            await self.clear_session()
        elif action == 'new':
            await self.create_new_session()
        else:
            console.print("[yellow]Usage:[/yellow]")
            console.print("  /history              - Show current session")
            console.print("  /history list         - Show all sessions")
            console.print("  /history sessions     - Show sessions by model")
            console.print("  /history load <id>    - Load specific session")
            console.print("  /history export [id]  - Export session")
            console.print("  /history clear        - Clear current session")
            console.print("  /history new          - Start new session")

    async def show_all_sessions(self):
        """Show all available sessions"""
        sessions = self.history.list_sessions()
        if not sessions:
            console.print("[yellow]No saved sessions found[/yellow]")
            return

        table = Table(title="All Sessions")
        table.add_column("Model", style="cyan")
        table.add_column("Session ID", style="green")
        table.add_column("Created", style="dim")
        table.add_column("Last Updated", style="dim")
        table.add_column("Entries", style="blue")
        table.add_column("Status", style="yellow")

        for model_name, model_sessions in sessions.items():
            for session in model_sessions:
                created = datetime.fromisoformat(session['created']).strftime("%m-%d %H:%M")
                updated = datetime.fromisoformat(session['last_updated']).strftime("%m-%d %H:%M")

                # Check if this is the current session
                status = "current" if (model_name == self.history.model_name and
                                     session['session_id'] == self.history.current_session_id) else ""

                table.add_row(
                    model_name,
                    session['session_id'],
                    created,
                    updated,
                    str(session['entry_count']),
                    status
                )

        console.print(table)

    async def show_sessions_by_model(self):
        """Show sessions organized by model"""
        sessions = self.history.list_sessions()
        if not sessions:
            console.print("[yellow]No saved sessions found[/yellow]")
            return

        for model_name, model_sessions in sessions.items():
            console.print(f"\n[cyan]📁 {model_name}[/cyan]")

            if not model_sessions:
                console.print("  [dim]No sessions[/dim]")
                continue

            for session in sorted(model_sessions, key=lambda s: s['created'], reverse=True):
                created = datetime.fromisoformat(session['created']).strftime("%Y-%m-%d %H:%M")
                status = " [yellow](current)[/yellow]" if (model_name == self.history.model_name and
                                                          session['session_id'] == self.history.current_session_id) else ""
                console.print(f"  🗨️  {session['session_id']} - {session['entry_count']} entries - {created}{status}")

