    async def clear_session(self):
        """Clear current session after confirmation"""
        if not self.history.entries:
            console.print("[yellow]Current session is already empty[/yellow]")
            return

        # Create operation info for confirmation gate
        operation = OperationInfo(
            operation_name="Clear Session",
            description=f"Clear current session ({self.history.current_session_id})",
            risk_level=RiskLevel.MEDIUM,
            affected_items=[f"{len(self.history.entries)} conversation entries"],
            consequences=[
                "Current conversation history will be cleared",
                "Session analytics will be reset",
                "Context will be lost"
            ],
            reversible=False,
            backup_available=True,  # Session can be exported first
            estimated_time="< 5 seconds"
        )

        # Require confirmation
        if not confirmation_gate.require_confirmation(operation):
            console.print("[yellow]Session clear cancelled[/yellow]")
            return

        # Backup current session before clearing
        if hasattr(self, 'session_manager'):
            self.session_manager.backup_session_data()

        self.history.clear()
        console.print("[green]Session cleared[/green]")

