    async def _generate_with_resources(self, prompt: str, system_prompt: str = None, task_type: str = 'standard', overrides: dict | None = None) -> str:
        """Generate text using resource-aware settings"""
        # Get current resource profile
        profile = resource_manager.get_profile_by_percentage(self.config.runtime.resources)

        # Create time budget based on mode
        if self.config.runtime.resources <= 25:
            # Fast mode: short budget
            budget = TimeBudget(total_seconds=15.0, started_at=time.time())
        elif self.config.runtime.resources <= 50:
            # Auto mode: moderate budget
            budget = TimeBudget(total_seconds=30.0, started_at=time.time())
        elif self.config.runtime.resources <= 75:
            # Think mode: generous budget
            budget = TimeBudget(total_seconds=60.0, started_at=time.time())
        else:
            # Maximum mode: very generous budget
            budget = TimeBudget(total_seconds=120.0, started_at=time.time())

        # Use time-sliced generation if enabled
        # Skip slicer in fast mode to reduce overhead
        if self.config.runtime.slice_generation and hasattr(self, 'time_slicer') and getattr(self, '_current_mode', 'auto') != 'fast':
            try:
                # Try time-sliced generation
                time_slicer = TimeSlicedGenerator(profile)
                return await time_slicer.generate_single_shot(
                    self.ollama_client, prompt, system_prompt, budget, task_type
                )
            except Exception as e:
                console.print(f"[dim yellow]Time-sliced generation failed, using standard: {e}[/dim yellow]")
                # Fall back to standard generation
                return await self.ollama_client.generate(prompt, system_prompt, task_type)
        else:
            # Standard generation with mode/policy-based caps and resource hints
            local_overrides = {}
            if overrides and isinstance(overrides, dict) and overrides:
                local_overrides = overrides
            else:
                # Fallback to mode-based overrides
                try:
                    local_overrides = self._compute_generation_overrides(task_type)
                except Exception:
                    local_overrides = {}

            # Streaming for fast/auto and think with thinktime budgets
            try:
                mode_key = getattr(self, '_current_mode', 'auto')
                thinktime_active = bool(getattr(self, '_think_budget_max_secs', None) or getattr(self, '_think_budget_min_secs', None))
                if (mode_key in ('fast', 'auto') and task_type in ('standard', 'structured')) or (mode_key == 'think' and thinktime_active):
                    start_ts = time.time()
                    chunks: list[str] = []
                    # Build streaming overrides similar to non-stream path
                    stream_overrides = dict(local_overrides)
                    options_override = stream_overrides.pop('options_override', None)
                    async for chunk in self.ollama_client.stream_generate(
                        prompt,
                        system_prompt,
                        task_type,
                        num_predict_override=stream_overrides.get('num_predict_override'),
                        temperature_override=stream_overrides.get('temperature_override'),
                        options_override=options_override,
                    ):
                        chunks.append(chunk)
                        # Respect soft max budget in thinktime
                        if mode_key == 'think' and thinktime_active:
                            max_secs = getattr(self, '_think_budget_max_secs', None)
                            if max_secs and (time.time() - start_ts) >= max_secs:
                                break
                    combined = ''.join(chunks).strip()
                    # Respect soft min budget in thinktime
                    if mode_key == 'think' and thinktime_active:
                        min_secs = getattr(self, '_think_budget_min_secs', None)
                        elapsed = time.time() - start_ts
                        if min_secs and elapsed < min_secs:
                            await asyncio.sleep(min_secs - elapsed)
                    if combined:
                        return combined
            except Exception:
                # Fallback to non-streaming below
                pass
            return await self.ollama_client.generate(
                prompt,
                system_prompt,
                task_type,
                **local_overrides,
            )

    def _update_orchestrator_resources(self):
        """Update orchestrator resource settings when config changes"""
        if hasattr(self, 'tool_orchestrator') and self.tool_orchestrator:
            self.tool_orchestrator.update_resource_profile()

    def _update_ollama_timeout_for_mode(self):
        """Update Ollama client timeout based on current resource mode"""
        if not hasattr(self, 'ollama_client') or not self.ollama_client:
            return

        # No hard read timeouts: ensure client uses no read timeout
        try:
            import httpx
            if hasattr(self.ollama_client, 'client') and self.ollama_client.client:
                self.ollama_client.client.timeout = httpx.Timeout(connect=10.0, read=None, write=60.0, pool=None)
                console.print(f"[dim]No hard read timeout; using soft budgets[/dim]")
        except Exception as e:
            console.print(f"[yellow]Warning: Could not update client timeout: {e}[/yellow]")

    def _enforce_hyphen_bullets(self, text: str, n: int) -> str | None:
        """Normalize to hyphen bullets and trim to exactly n lines if possible.

        - Converts numbered or '*' bullets to '- '
        - Drops Markdown headings and empty lines
        - If fewer than n items remain, return original text
        """
        raw_lines = [ln.rstrip() for ln in text.splitlines()]
        norm: list[str] = []
        for ln in raw_lines:
            s = ln.strip()
            if not s:
                continue
            # Drop headings and section titles
            if s.startswith('#') or s.startswith('**') or s.endswith(':'):
                continue
            # Normalize numbered lists: '1. Item' or '1) Item'
            import re as _re
            if _re.match(r"^\d+[\.)]\s+", s):
                s = '- ' + _re.sub(r"^\d+[\.)]\s+", "", s)
            # Normalize star bullets
            if s.startswith('* '):
                s = '- ' + s[2:]
            # Keep only hyphen bullets
            if s.startswith('- '):
                norm.append(s)
        if not norm:
            return None
        if len(norm) >= n:
            return "\n".join(norm[:n])
        return None

    def _compute_generation_overrides(self, task_type: str) -> Dict[str, Optional[float]]:
        """Map /mode and task_type to generation limits and timeouts.

        Returns keys for OllamaClient.generate: num_predict_override,
        temperature_override, read_timeout_override.
        """
        mode = getattr(self, '_current_mode', 'auto') or 'auto'
        think_secs = getattr(self, '_think_budget_secs', None)

        # Defaults per mode (tuned for snappy structured lists in fast/auto)
        caps_fast = {'standard': 120, 'structured': 90, 'reasoning': 200}
        caps_auto = {'standard': 300, 'structured': 220, 'reasoning': 450}
        caps_think = {'standard': 600, 'structured': 350, 'reasoning': 900}

        if mode.startswith('fast'):
            cap = caps_fast.get(task_type, 256)
            read_to = None
        elif mode.startswith('think'):
            if think_secs:
                # Approximate tokens per second for small models
                tps = 10.0
                est = int(max(50, min(self.config.model.max_tokens, tps * float(think_secs))))
                if task_type == 'structured':
                    est = min(est, 400)
                cap = est
                read_to = float(think_secs)
            else:
                cap = caps_think.get(task_type, 800)
                read_to = None
        else:
            # auto / smart / custom_xx
            cap = caps_auto.get(task_type, 400)
            read_to = None

        temp = None
        if task_type == 'structured':
            # Lower temperature for tighter, less verbose lists
            temp = max(0.0, float(getattr(self.config.model, 'temperature', 0.7)) - 0.15)

        ov = {'num_predict_override': cap, 'temperature_override': temp}
        return ov

    async def handle_quality_command(self, command: str):
        """Handle quality system commands"""
        if not self.quality_manager:
            console.print("[yellow]Quality Recovery System is not available or disabled[/yellow]")
            return

        if command == 'status' or not command:
            try:
                status = self.quality_manager.get_quality_status()
                console.print(f"🎯 Quality System: [green]{status['system_health']}[/green]")

                quality_metrics = status.get('quality_system_status', {}).get('master_metrics', {})
                if quality_metrics:
                    instant_coverage = quality_metrics.get('instant_coverage_rate', 0)
                    avg_response_time = quality_metrics.get('average_response_time', 0)
                    console.print(f"📊 Instant Coverage: [cyan]{instant_coverage:.1%}[/cyan]")
                    console.print(f"⚡ Avg Response Time: [cyan]{avg_response_time:.3f}s[/cyan]")

                integration_metrics = status.get('integration_metrics', {})
                if integration_metrics:
                    total_requests = integration_metrics.get('total_requests', 0)
                    quality_used = integration_metrics.get('quality_system_used', 0)
                    fallback_used = integration_metrics.get('fallback_used', 0)
                    console.print(f"📈 Total Requests: {total_requests}")
                    console.print(f"✨ Quality System: {quality_used} | 🔄 Fallbacks: {fallback_used}")

            except Exception as e:
                console.print(f"[red]Error getting quality status: {e}[/red]")

        elif command.startswith('mode '):
            mode = command.split()[-1]
            try:
                self.quality_manager.set_quality_mode(mode)
                console.print(f"🔧 Quality mode set to: [green]{mode}[/green]")
            except ValueError as e:
                console.print(f"[red]Error: {e}[/red]")
                console.print("Available modes: fast, auto, think, learning")
            except Exception as e:
                console.print(f"[red]Error setting quality mode: {e}[/red]")

        elif command == 'optimize':
            try:
                result = self.quality_manager.optimize_quality_system()
                optimizations = result.get('optimizations_applied', [])
                console.print(f"🚀 Applied {len(optimizations)} optimizations:")
                for opt in optimizations[:5]:  # Show first 5
                    console.print(f"  • {opt}")
                if len(optimizations) > 5:
                    console.print(f"  ... and {len(optimizations) - 5} more")
            except Exception as e:
                console.print(f"[red]Error optimizing quality system: {e}[/red]")

        elif command == 'enable':
            try:
                self.quality_manager.enable_quality_system()
                console.print("[green]Quality system enabled[/green]")
            except Exception as e:
                console.print(f"[red]Error enabling quality system: {e}[/red]")

        elif command == 'disable':
            try:
                self.quality_manager.disable_quality_system()
                console.print("[yellow]Quality system disabled - using original processing[/yellow]")
            except Exception as e:
                console.print(f"[red]Error disabling quality system: {e}[/red]")

        else:
            console.print("[yellow]Available quality commands:[/yellow]")
            console.print("  /quality status    - Show quality system status")
            console.print("  /quality mode <mode> - Set quality mode (fast/auto/think/learning)")
            console.print("  /quality optimize  - Optimize quality system")
            console.print("  /quality enable    - Enable quality system")
            console.print("  /quality disable   - Disable quality system")

