    async def handle_coding_command(self, args: str):
        """Handle /coding command for managing coding experiments."""
        parts = args.split()
        command = parts[0] if parts else "status"

        import os
        version = os.getenv('OPENCODE_VERSION', 'default')
        experiments_dir = Path('versions') / version / 'experiments'
        experiments_dir.mkdir(exist_ok=True)
        state_file = experiments_dir / '.state.json'

        def get_state():
            if state_file.exists():
                try:
                    return json.loads(state_file.read_text())
                except (json.JSONDecodeError, FileNotFoundError):
                    return {}
            return {}

        def save_state(state):
            try:
                tmp = state_file.with_suffix('.tmp')
                tmp.write_text(json.dumps(state, indent=2))
                tmp.replace(state_file)
            except Exception:
                state_file.write_text(json.dumps(state, indent=2))

        if command == "new":
            exp_name = parts[1] if len(parts) > 1 else f"exp_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
            # Sanitize name
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_-]+$', exp_name):
                    console.print("[red]Invalid experiment name. Use letters, numbers, '-', '_' only.[/red]")
                    return
            except Exception:
                pass
            exp_dir = experiments_dir / exp_name

            op_info = OperationInfo(
                operation_name="Create Coding Experiment",
                description=f"Create a new experiment sandbox: {exp_dir}",
                risk_level=RiskLevel.LOW,
                affected_items=[str(exp_dir)],
                consequences=["A new directory will be created."],
                reversible=True,
                backup_available=False
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Experiment creation cancelled.[/yellow]")
                return

            existed = exp_dir.exists()
            exp_dir.mkdir(exist_ok=True)
            (exp_dir / 'code').mkdir(exist_ok=True)
            (exp_dir / 'output').mkdir(exist_ok=True)
            (exp_dir / 'README.md').write_text(f"# Experiment: {exp_name}\n\nCreated: {datetime.now().isoformat()}")
            (exp_dir / 'code' / 'hello.txt').write_text("HI!")

            state = get_state()
            state['active_experiment'] = str(exp_dir)
            state['last_created'] = str(exp_dir)
            save_state(state)

            if existed:
                console.print(f"[yellow]Using existing experiment: {exp_dir}[/yellow]")
            else:
                console.print(f"[green]✓ Created new experiment: {exp_dir}[/green]")
            console.print(f"[bold]Active experiment set to: {exp_name}[/bold]")

        elif command in ["list", "ls"]:
            console.print(f"[bold]Experiments in version '{version}':[/bold]")
            state = get_state()
            active_exp = state.get('active_experiment')

            for exp in sorted(experiments_dir.iterdir()):
                if exp.is_dir() and not exp.name.startswith('.'):
                    marker = " (active)" if active_exp and Path(active_exp).name == exp.name else ""
                    console.print(f"- {exp.name}{marker}")

        elif command == "where":
            state = get_state()
            active_exp = state.get('active_experiment')
            if active_exp:
                console.print(f"Active experiment path: {active_exp}")
            else:
                console.print("[yellow]No active experiment.[/yellow]")

        elif command == "open":
            if len(parts) < 2:
                console.print("[red]Usage: /coding open <experiment_name>[/red]")
                return

            exp_name = parts[1]
            # Sanitize
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_-]+$', exp_name):
                    console.print("[red]Invalid experiment name. Use letters, numbers, '-', '_' only.[/red]")
                    return
            except Exception:
                pass
            exp_dir = experiments_dir / exp_name
            if not exp_dir.is_dir():
                console.print(f"[red]Experiment '{exp_name}' not found.[/red]")
                return

            # Confirmation to switch active pointer
            op_info = OperationInfo(
                operation_name="Open Coding Experiment",
                description=f"Set active experiment to: {exp_name}",
                risk_level=RiskLevel.LOW,
                affected_items=[str(state_file)],
                consequences=["The active experiment pointer will be changed."],
                reversible=True,
                backup_available=False
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return

            state = get_state()
            state['active_experiment'] = str(exp_dir)
            save_state(state)
            console.print(f"Active experiment set to: {exp_name}")
            try:
                # Update tool manager working directory
                self.tool_manager.working_dir = exp_dir.resolve()
            except Exception:
                pass

        elif command == "gen":
            # /coding gen <file.py> <optional text>
            if len(parts) < 2:
                console.print("[red]Usage: /coding gen <file.py> [text][/red]")
                return
            target = parts[1]
            try:
                import re as _re
                if not _re.match(r'^[A-Za-z0-9_.-]+$', target):
                    console.print("[red]Invalid filename[/red]")
                    return
            except Exception:
                pass
            state = get_state()
            active_exp = state.get('active_experiment')
            if not active_exp:
                console.print("[yellow]No active experiment set. Use /coding new or /coding open first.[/yellow]")
                return
            exp_dir = Path(active_exp)
            code_dir = exp_dir / 'code'
            code_dir.mkdir(exist_ok=True)
            dest = code_dir / target
            content = " ".join(parts[2:]) if len(parts) > 2 else "# Auto-generated script\nprint('HI!')\n"
            # Confirm write
            op_info = OperationInfo(
                operation_name="Create Script",
                description=f"Create/overwrite {dest.name} in active experiment",
                risk_level=RiskLevel.MEDIUM,
                affected_items=[str(dest)],
                consequences=["File will be created or overwritten"],
                reversible=True,
                backup_available=True
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return
            try:
                dest.write_text(content)
                console.print(f"[green]✓ Wrote {dest}[/green]")
                # Keep tools inside experiment
                self.tool_manager.working_dir = exp_dir.resolve()
            except Exception as e:
                console.print(f"[red]Write failed: {e}[/red]")
                return

        elif command == "run":
            # /coding run <file.py>
            if len(parts) < 2:
                console.print("[red]Usage: /coding run <file.py>[/red]")
                return
            target = parts[1]
            state = get_state()
            active_exp = state.get('active_experiment')
            if not active_exp:
                console.print("[yellow]No active experiment set. Use /coding new or /coding open first.[/yellow]")
                return
            exp_dir = Path(active_exp)
            code_path = exp_dir / 'code' / target
            if not code_path.exists():
                console.print(f"[red]Script not found: {code_path}[/red]")
                return
            # Confirm execution
            op_info = OperationInfo(
                operation_name="Run Script",
                description=f"Execute {target} in active experiment",
                risk_level=RiskLevel.LOW,
                affected_items=[str(code_path)],
                consequences=["Script will run and may write outputs"],
                reversible=True,
                backup_available=True
            )
            if not confirmation_gate.require_confirmation(op_info):
                console.print("[yellow]Operation cancelled.[/yellow]")
                return
            try:
                # Use bash_execute tool with safe cwd and preferred interpreter
                interp = self._python_interpreter()
                result = await self.tool_manager.execute_tool(
                    'bash_execute',
                    command=f"{interp} {code_path.name}",
                    cwd=str((exp_dir / 'code').resolve())
                )
                if result.success:
                    console.print(f"[cyan]{result.output}\n[/cyan]" if result.output else "[green]✓ Script finished[/green]")
                else:
                    console.print(f"[red]Script failed: {result.error}[/red]")
            except Exception as e:
                console.print(f"[red]Execution error: {e}[/red]")
                return

        elif command == "status":
            state = get_state()
            active_exp = state.get('active_experiment')
            if active_exp:
                console.print(f"Active experiment: {Path(active_exp).name}")
            else:
                console.print("[yellow]No active experiment set.[/yellow]")
        else:
            console.print(f"[red]Unknown command: /coding {command}")
            console.print("Available commands: new, list, where, open, status")
